                <div class="tab-item" :class="{ active: activeTab === '资产' }" @click="handleTabSwitch('资产')">资产</div>
                <div class="tab-item" :class="{ active: activeTab === '简介' }" @click="handleTabSwitch('简介')">简介</div>
                <div class="tab-item" :class="{ active: activeTab === '调度' }" @click="handleTabSwitch('调度')">调度</div>
