                                <button class="zoom-btn">- 缩小</button>
                            </div>
                        </div>
                    </div>

                    <!-- 资产页面 -->
                    <div v-if="activeTab === '资产'" class="asset-page">
                        <div class="page-content">
                            <div class="page-title">资产信息</div>
                            <div class="page-text">资产页面内容</div>
                        </div>
                    </div>

                    <!-- 简介页面 -->
                    <div v-if="activeTab === '简介'" class="intro-page">
                        <div class="page-content">
                            <div class="page-title">泵房简介</div>
                            <div class="page-text">{{ currentPumpRoom.description }}</div>
                        </div>
                    </div>

                    <!-- 调度页面 -->
                    <div v-if="activeTab === '调度'" class="dispatch-page">
                        <div class="page-content">
                            <div class="page-title">调度信息</div>
