<script>
import { markRaw } from 'vue'
import * as echarts from 'echarts'

export default {
    name: 'BaiduMapWithPopup',
    props: {
        center: {
            type: Object,
            default: () => ({ lng: 116.404, lat: 39.915 })
        },
        zoom: {
            type: Number,
            default: 14
        },
        currentMenu: {
            type: String,
            default: '分区计量'
        }
    },
    data() {
        return {
            activeTab: '实时',
            mapLoaded: false,
            showPumpRoomPopup: false,
            showPipelinePopup: false,
            mapOverlays: [] // 存储所有覆盖物，用于动态切换时清除
        };
    },
    watch: {
        // 监听菜单变化，动态切换地图显示
        currentMenu() {
            this.switchMapDisplay()
        }
    },
    methods: {
        handleReady() {
            // 使用 vue-baidu-map-3x 组件的方式初始化地图
            if (!this.$refs.baiduMap || !this.$refs.baiduMap.map) {
                console.error('百度地图组件未初始化完成')
                return
            }
            const map = this.$refs.baiduMap.map

            // 设置地图样式
            map.setMapStyleV2({
                styleId: 'd28f7988413149b7b956a02501d09a2d'
            });

            // 动态切换地图显示
            this.switchMapDisplay()

            // 地图加载完成
            setTimeout(() => {
                this.mapLoaded = true
            }, 1000);
        },

        // 清除所有覆盖物
        clearAllOverlays() {
            const map = this.$refs.baiduMap.map
            // 清除所有存储的覆盖物
            this.mapOverlays.forEach(overlay => {
                if (overlay.type === 'container') {
                    // 处理自定义容器元素
                    if (overlay.element && overlay.element.parentNode) {
                        overlay.element.parentNode.removeChild(overlay.element)
                    }
                } else {
                    // 处理普通BMap覆盖物
                    map.removeOverlay(overlay)
                }
            })
            // 清空覆盖物数组
            this.mapOverlays = []
        },

        // 动态切换地图显示
        switchMapDisplay() {
            this.clearAllOverlays()
            if (this.currentMenu === '分区计量') {
                this.addWaterSupplyAreas()
            } else {
                this.addPumpMarkers()
                this.addPipelineMarkers()
            }
        },

        // 泵打点
        addPumpMarkers() {
            const map = this.$refs.baiduMap.map

            // 创建自定义图标
            const myIcon = new window.BMap.Icon(
                require('@/assets/mapIcon/泵房定位.png'),
                new window.BMap.Size(90, 138) // 保持原尺寸
            )
            // 设置图标缩放，缩小为原尺寸的50%
            myIcon.setImageSize(new window.BMap.Size(45, 69))


            // 多打一些点：在地图中心周围添加 8 个泵房点位
            const centerLng = 116.404
            const centerLat = 39.915
            const positions = [
                [centerLng, centerLat],
                [centerLng + 0.012, centerLat],
                [centerLng - 0.0015, centerLat + 0.0115]
            ]
            positions.forEach(([lng, lat], index) => {
                const marker = new window.BMap.Marker(
                    new window.BMap.Point(lng, lat),
                    { icon: myIcon }
                )
                // 添加点击事件监听
                marker.addEventListener('click', () => {
                    this.showPumpRoomPopup = true
                    this.currentPumpRoom = {
                        id: index + 1,
                        name: `金泰花园二供泵房${index + 1}`,
                        time: '2024-06-27 09:38:55',
                        inletPressure: '0.24 Mpa',
                        outletPressure: '0.26 Mpa',
                        flow: '0 m³/h'
                    }
                    setTimeout(() => {
                        this.initPumpChart()
                    }, 200);
                })
                map.addOverlay(marker)
                this.mapOverlays.push(marker) // 存储覆盖物
                // 添加点位标题
                const label = new window.BMap.Label(`金泰花园二供泵房${index + 1}`, {
                    position: new window.BMap.Point(lng, lat),
                    offset: new window.BMap.Size(-60, 30) // 调整标签位置在图标下方
                })
                // 设置标签样式
                label.setStyle({
                    color: '#fff',
                    fontSize: '12px',
                    backgroundColor: 'rgba(0, 0, 0, 0.7)',
                    border: '1px solid #01ABFB',
                    borderRadius: '4px',
                    padding: '2px 8px',
                    width: '120px',
                    whiteSpace: 'nowrap',
                    textAlign: 'center'
                })
                map.addOverlay(label)
                this.mapOverlays.push(label) // 存储覆盖物
            })
        },

        handleTabSwitch(tab) {
            this.activeTab = tab;

            if (tab === '实时') {
                setTimeout(() => {
                    if (this.showPumpRoomPopup) {
                        this.initPumpChart()
                    } else if (this.showPipelinePopup) {
                        this.initPipelineChart()
                    }
                }, 100)
            }
        },
        handleClose() {
            this.showPumpRoomPopup = false
        },
        handleClosePipeline() {
            this.showPipelinePopup = false
        },
        // 管网打点
        addPipelineMarkers() {
            const map = this.$refs.baiduMap.map

            // 创建自定义图标
            const pipelineIcon = new window.BMap.Icon(
                require('@/assets/mapIcon/管网定位.png'),
                new window.BMap.Size(90, 138) // 保持原尺寸
            )
            // 设置图标缩放，缩小为原尺寸的50%
            pipelineIcon.setImageSize(new window.BMap.Size(45, 69))


            // 管网点位
            const centerLng = 116.404
            const centerLat = 39.915
            const pipelinePositions = [
                [centerLng - 0.01, centerLat - 0.005],
                [centerLng + 0.005, centerLat - 0.01],
                [centerLng - 0.008, centerLat + 0.008],
                [centerLng + 0.008, centerLat + 0.005]
            ]
            pipelinePositions.forEach(([lng, lat], index) => {
                const marker = new window.BMap.Marker(
                    new window.BMap.Point(lng, lat),
                    {
                        icon: pipelineIcon,
                        offset: new window.BMap.Size(-25, -25) // 图标居中偏移
                    }
                )
                // 添加点击事件监听
                marker.addEventListener('click', () => {
                    this.showPipelinePopup = true
                    this.currentPipeline = {
                        id: index + 1,
                        name: `曹雪芹东道${index + 1}号管网`,
                        time: '2024-06-27 09:38:55',
                        pressure: '0.65 Mpa',
                        flow: '63 m³/h',
                        ph: '6.9',
                        dissolvedOxygen: '2.2 mg/L',
                        conductivity: '0.07 μS/cm',
                        turbidity: '0.1 NTU',
                        temperature: '20°C'
                    }
                    setTimeout(() => {
                        this.initPipelineChart()
                    }, 200);
                })
                map.addOverlay(marker)
                this.mapOverlays.push(marker) // 存储覆盖物
                // 添加点位标题
                const label = new window.BMap.Label(`金泰花园管网${index + 1}`, {
                    position: new window.BMap.Point(lng, lat),
                    offset: new window.BMap.Size(-60, 30) // 调整标签位置在图标下方
                })
                // 设置标签样式
                label.setStyle({
                    color: '#fff',
                    fontSize: '12px',
                    backgroundColor: 'rgba(0, 0, 0, 0.7)',
                    border: '1px solid #01ABFB',
                    borderRadius: '4px',
                    padding: '2px 8px',
                    width: '120px',
                    whiteSpace: 'nowrap',
                    textAlign: 'center'
                })
                map.addOverlay(label)
                this.mapOverlays.push(label) // 存储覆盖物
            })
        },
        initPipelineChart() {
            const chartDom = this.$refs.pipelineChart
            if (!chartDom) return
            const myChart = markRaw(echarts.init(chartDom))
            const option = {
                title: {
                    text: '',
                    left: 'center',
                    textStyle: {
                        color: '#00d4ff'
                    }
                },
                tooltip: {
                    trigger: 'axis'
                },
                legend: {
                    data: ['压力', '流量'],
                    top: 0,
                    textStyle: {
                        color: '#fff'
                    }
                },
                grid: {
                    left: '3%',
                    right: '4%',
                    bottom: '3%',
                    containLabel: true
                },
                xAxis: {
                    type: 'category',
                    boundaryGap: false,
                    data: ['00:00', '04:00', '08:00', '12:00', '16:00', '20:00'],
                    axisLine: {
                        lineStyle: {
                            color: '#fff'
                        }
                    },
                    axisLabel: {
                        color: '#fff'
                    }
                },
                yAxis: [
                    {
                        type: 'value',
                        name: 'Mpa',
                        axisLine: {
                            lineStyle: {
                                color: '#0082FB'
                            }
                        },
                        axisLabel: {
                            color: '#fff'
                        }
                    },
                    {
                        type: 'value',
                        name: 'm³/h',
                        axisLine: {
                            lineStyle: {
                                color: '#00FCFD'
                            }
                        },
                        axisLabel: {
                            color: '#fff'
                        },
                        position: 'right'
                    }
                ],
                series: [
                    {
                        name: '压力',
                        type: 'line',
                        yAxisIndex: 0,
                        data: [0.6, 0.7, 0.65, 0.7, 0.68, 0.65],
                        itemStyle: {
                            color: '#0082FB'
                        },
                        lineStyle: {
                            width: 2
                        }
                    },
                    {
                        name: '流量',
                        type: 'line',
                        yAxisIndex: 1,
                        data: [60, 65, 63, 62, 64, 63],
                        itemStyle: {
                            color: '#00FCFD'
                        },
                        lineStyle: {
                            width: 2
                        }
                    }
                ]
            }
            myChart.setOption(option)
            window.addEventListener('resize', () => {
                myChart.resize()
            })
        },
        // 绘制供水区域
        addWaterSupplyAreas() {
            const map = this.$refs.baiduMap.map

            // 供水区域数据 - 调整坐标，避免与点位重叠（进一步远离中心点）
            const waterSupplyAreas = [
                {
                    name: '丰润区供水',
                    points: [
                        new window.BMap.Point(116.374, 39.925),
                        new window.BMap.Point(116.384, 39.925),
                        new window.BMap.Point(116.384, 39.915),
                        new window.BMap.Point(116.374, 39.915)
                    ],
                    data: {
                        '供水量': '1198627.03m³',
                        '漏损量': '444.24m³',
                        '漏损率': '0.04%',
                        '夜间最小流量': '1198627.03m³'
                    }
                },
                {
                    name: '丰润区供水',
                    points: [
                        new window.BMap.Point(116.424, 39.905),
                        new window.BMap.Point(116.434, 39.905),
                        new window.BMap.Point(116.434, 39.895),
                        new window.BMap.Point(116.424, 39.895)
                    ],
                    data: {
                        '供水量': '1198627.03m³',
                        '漏损量': '444.24m³',
                        '漏损率': '0.04%',
                        '夜间最小流量': '1198627.03m³'
                    }
                }
            ]

            // 绘制每个供水区域
            waterSupplyAreas.forEach((area) => {
                // 创建多边形
                const polygon = new window.BMap.Polygon(area.points, {
                    strokeColor: '#00BFFB',
                    strokeWeight: 2,
                    strokeOpacity: 0.8,
                    fillColor: '#00BFFB',
                    fillOpacity: 0.2
                })
                map.addOverlay(polygon)
                this.mapOverlays.push(polygon) // 存储覆盖物

                // 获取多边形中心点
                const bounds = polygon.getBounds()
                const center = bounds.getCenter()

                // 创建信息面板元素（每个多边形一个独立面板）
                const panelDiv = document.createElement('div')
                panelDiv.className = 'water-supply-info'
                panelDiv.style.display = 'none' // 默认隐藏
                panelDiv.style.position = 'absolute'
                panelDiv.style.zIndex = '1000' // 确保显示在最上层

                // 添加到地图markerPane
                map.getPanes().markerPane.appendChild(panelDiv)
                this.mapOverlays.push({ type: 'panel', element: panelDiv }) // 存储面板

                // 为多边形添加点击事件
                polygon.addEventListener('click', () => {
                    // 更新面板内容，添加关闭按钮
                    panelDiv.innerHTML = `
                        <div class="info-title">
                            ${area.name}
                            <button class="close-btn" style="float: right; background: none; border: none; color: #00BFFB; cursor: pointer; font-size: 16px; padding: 0; margin: 0;">×</button>
                        </div>
                        <div class="info-content">
                            <div class="info-item">
                                <span class="info-label">供水量</span>
                                <span class="info-value">${area.data['供水量']}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">漏损量</span>
                                <span class="info-value">${area.data['漏损量']}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">漏损率</span>
                                <span class="info-value">${area.data['漏损率']}</span>
                            </div>
                            <div class="info-item">
                                <span class="info-label">夜间最小流量</span>
                                <span class="info-value">${area.data['夜间最小流量']}</span>
                            </div>
                        </div>
                    `

                    // 计算并设置面板位置
                    const pixel = map.pointToOverlayPixel(center)
                    panelDiv.style.left = pixel.x - 110 + 'px' // 110是面板宽度的一半
                    panelDiv.style.top = pixel.y - 150 + 'px' // 调整垂直位置
                    panelDiv.style.display = 'block' // 显示面板

                    // 添加关闭按钮事件
                    const closeBtn = panelDiv.querySelector('.close-btn')
                    if (closeBtn) {
                        closeBtn.onclick = () => {
                            panelDiv.style.display = 'none'
                        }
                    }

                    // 设置3秒后自动关闭面板
                    setTimeout(() => {
                        panelDiv.style.display = 'none'
                    }, 3000)
                })
            })

            // 移除复杂的地图点击事件，避免冲突
            // 面板通过关闭按钮或自动关闭
        },

        initPumpChart() {
            const chartDom = this.$refs.pumpChart
            if (!chartDom) return
            const myChart = markRaw(echarts.init(chartDom))
            const option = {
